query:
UPDATE v2Stages SET stageName='摩诘念珠', weaponEmoji='📿', storyBefore='深山之中，传来一阵低沉的诵经声。讲书人樊登被毒龙封印于此，你踏入竹林，感受到一股禅意扑面而来。「深林人不知，明月来相照。」——这是王维留下的线索，也是破除封印的第一把钥匙。', storyAfter='念珠轻转，竹林中的迷雾渐渐消散。你成功破解了第一道封印，樊登的声音从远处传来：「继续前行，还有更深的禅境等待你。」' WHERE stageNumber=1;
UPDATE v2Stages SET stageName='空山梵钟', weaponEmoji='🔔', storyBefore='穿过竹林，你来到一座古寺废墟。钟声从虚空中响起，却不知源头。「古木无人径，深山何处钟。」——王维的诗句在风中回荡，指引着你寻找那口沉默千年的梵钟。', storyAfter='梵钟一响，山谷回声震动，封印的锁链松动了一格。空山的禅意在你心中生根，你离樊登又近了一步。' WHERE stageNumber=2;
UPDATE v2Stages SET stageName='清泉石剑', weaponEmoji='💧', storyBefore='山居秋暝，明月高悬。你在石上发现一把被清泉浸润千年的古剑。「明月松间照，清泉石上流。」——剑身上刻着王维的诗句，只有真正领悟山居之静的人，才能拔出此剑。', storyAfter='清泉石剑在手，第一章的封印彻底破除。空山禅音章节完成，你的心境如明月般澄澈。' WHERE stageNumber=3;
UPDATE v2Stages SET stageName='芙蓉冰心', weaponEmoji='🌸', storyBefore='走出深山，你来到大漠边关。风沙遮天蔽日，一座孤城矗立在黄沙之中。城楼上，王昌龄的诗句如同护城符咒：「洛阳亲友如相问，一片冰心在玉壶。」——只有冰心不改，才能穿透这片幻境。', storyAfter='冰心如玉，边关幻境中的第一道铁骑围攻被你击退。沙场上，一朵芙蓉在风中傲然盛开。' WHERE stageNumber=4;
UPDATE v2Stages SET stageName='夜光玉杯', weaponEmoji='🏺', storyBefore='大漠夜宴，胡姬捧杯，琵琶声声催。「葡萄美酒夜光杯，欲饮琵琶马上催。」——王翰的《凉州词》化作一道幻境，杯中美酒是陷阱，还是破敌的机缘？', storyAfter='夜光玉杯高举，酒光折射出毒龙的弱点。你在边塞幻境中找到了突破口，继续前行。' WHERE stageNumber=5;
UPDATE v2Stages SET stageName='哥舒夜刀', weaponEmoji='🗡️', storyBefore='北斗七星高悬，大漠夜风呼啸。「北斗七星高，哥舒夜带刀。」——西鄙人的《哥舒歌》在此化为一把寒光闪闪的夜刀，斩断塞上幻境的最后枷锁。', storyAfter='哥舒夜刀出鞘，边塞幻境轰然崩塌。第二章塞上风云完成，你的意志如大漠长风，无坚不摧。' WHERE stageNumber=6;
UPDATE v2Stages SET stageName='飞泉灵剑', weaponEmoji='⚡', storyBefore='踏入仙侠神话之境，你面前出现一道飞瀑，剑气纵横。「誓令疏勒出飞泉，不似将军空尔为。」——王维《老将行》中的誓言化为灵剑，等待真正有担当之人来执掌。', storyAfter='飞泉灵剑在手，仙侠幻境的第一层障碍被破除。雷光在云端闪烁，更大的考验即将到来。' WHERE stageNumber=7;

